#include<bits/stdc++.h>
using namespace std;
int n,m,k;
int fa[800010],siz[800010];
bool flag;
struct Stack
{
    int x,y;
}s[3200010];
int top;
struct edge
{
    int x,y;
};
vector<edge> t[1600010];
int find(int x)
{
    while(x!=fa[x])
    {
        x=fa[x];
    }
    return x;
}
void merge(int x,int y)
{
    int a=find(x),b=find(y);
    if(a==b)
    {
        return;
    }
    if(siz[a]>siz[b])
    {
        swap(a,b);
    }
    s[++top]=(Stack){a,b};
    siz[b]+=siz[a];
    fa[a]=b;
}
void update(int x,int l,int r,int L,int R,edge v)
{
    if(L>R||l>R||L>r)
    {
        return;
    }
    if(L<=l&&r<=R)
    {
        t[x].push_back(v);
        return;
    }
    int mid=(l+r)>>1;
    update(x<<1,l,mid,L,R,v);
    update(x<<1|1,mid+1,r,L,R,v);
}
void solve(int x,int l,int r)
{
    int lst=top;
    for(auto i:t[x])
    {
        merge(i.x,i.y);
    }
    if(l==r)
    {
        if(siz[find(1)]==n)
        {
            flag=true;
        }
    }
    else
    {
        int mid=(l+r)>>1;
        solve(x<<1,l,mid);
        solve(x<<1|1,mid+1,r);
    }
    while(top>lst)
    {
        int k=s[top].x;
        while(k!=fa[k])
        {
            k=fa[k];
            siz[k]-=siz[s[top].x];
        }
        fa[s[top].x]=s[top].x;
        top--;
    }
}
int U[200010],V[200010],W[200010];
void clear()
{
    for(int i=1;i<=800000;i++)
    {
        siz[i]=1;
        fa[i]=i;
        t[i].clear();
    }
    flag=false;
    top=0;
}
bool check(int mid)
{
    clear();
    for(int i=1;i<=m;i++)if(U[i]!=V[i])
    {
        update(1,1,80000,W[i],W[i]+mid,(edge){U[i],V[i]});
    }
    solve(1,1,80000);
    return flag;
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        scanf("%d%d%d",&U[i],&V[i],&W[i]);
    }
    int l=0,r=20000,best;
    while(l<=r)
    {
        int mid=(l+r)>>1;
        if(check(mid))
        {
            r=mid-1;
            best=mid;
        }
        else
        {
            l=mid+1;
        }
    }
    printf("%d",best);
    return 0;
}
